CREATE TYPE "AircraftSyncStatus" AS ENUM ('LOCAL_DRAFT','PUBLISHING','SYNCED','UPDATE_PENDING','SYNC_ERROR','MISSING');
ALTER TABLE "Aircraft" ADD COLUMN "name" TEXT, ADD COLUMN "containerUnits" INTEGER, ADD COLUMN "selcal" TEXT, ADD COLUMN "finNumber" TEXT, ADD COLUMN "hexcode" TEXT, ADD COLUMN "hiddenInPhoenix" BOOLEAN NOT NULL DEFAULT false, ADD COLUMN "vamsysInternalRemarks" TEXT, ADD COLUMN "internalNotes" TEXT, ADD COLUMN "simbriefOverrides" JSONB, ADD COLUMN "imageUrl" TEXT, ADD COLUMN "imageAttribution" TEXT, ADD COLUMN "imageLinkback" TEXT, ADD COLUMN "syncStatus" "AircraftSyncStatus" NOT NULL DEFAULT 'LOCAL_DRAFT', ADD COLUMN "sourceUpdatedAt" TIMESTAMP(3), ADD COLUMN "lastSeenAt" TIMESTAMP(3), ADD COLUMN "lastSyncedAt" TIMESTAMP(3), ADD COLUMN "lastPublishedAt" TIMESTAMP(3), ADD COLUMN "lastSyncError" TEXT;
UPDATE "Aircraft" SET "syncStatus"='SYNCED', "lastSeenAt"=NOW(), "lastSyncedAt"=NOW() WHERE "vamsysAircraftId" IS NOT NULL;
CREATE INDEX "Aircraft_fleetId_idx" ON "Aircraft"("fleetId");CREATE INDEX "Aircraft_syncStatus_idx" ON "Aircraft"("syncStatus");CREATE INDEX "Aircraft_hiddenInPhoenix_idx" ON "Aircraft"("hiddenInPhoenix");
